/// Extracts the first grapheme cluster of the string.
/// Fails with an error if the string is empty.
///
/// If `count` is given, returns an array of the first `count` grapheme
/// clusters instead of a single string. Fails with an error if the
/// string has fewer than `count` grapheme clusters.
#[func]
pub fn first(
    &self,
    /// Number of characters to return as an array. If omitted, returns a
    /// single string.
    #[named]
    count: Option<usize>,
) -> StrResult<Value> {
    match count {
        None => self
            .0
            .graphemes(true)
            .next()
            .map(|s| Str::from(s).into_value())
            .ok_or_else(string_is_empty),
        Some(count) => {
            let graphemes: Vec<_> = self.0.graphemes(true).take(count).collect();
            if graphemes.len() < count {
                return Err(count_exceeds_length(count, self.0.graphemes(true).count()));
            }
            Ok(Array::from_iter(graphemes.into_iter().map(|s| Str::from(s).into_value()))
                .into_value())
        }
    }
}

/// Extracts the last grapheme cluster of the string.
/// Fails with an error if the string is empty.
///
/// If `count` is given, returns an array of the last `count` grapheme
/// clusters instead of a single string. Fails with an error if the
/// string has fewer than `count` grapheme clusters.
#[func]
pub fn last(
    &self,
    /// Number of characters to return as an array. If omitted, returns a
    /// single string.
    #[named]
    count: Option<usize>,
) -> StrResult<Value> {
    match count {
        None => self
            .0
            .graphemes(true)
            .next_back()
            .map(|s| Str::from(s).into_value())
            .ok_or_else(string_is_empty),
        Some(count) => {
            let total = self.0.graphemes(true).count();
            if count > total {
                return Err(count_exceeds_length(count, total));
            }
            Ok(Array::from_iter(
                self.0
                    .graphemes(true)
                    .skip(total - count)
                    .map(|s| Str::from(s).into_value()),
            )
            .into_value())
        }
    }
}

